using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var context = CreateContext(dbName);
            SeedData(context);
            return context;
        }

        /// <summary>
        /// Drains the static NotificationService queue to prevent cross-test contamination.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        private static void SeedData(SchoolContext context)
        {
            var instructors = new[]
            {
                new Instructor { LastName = "Abercrombie", FirstMidName = "Kim", HireDate = DateTime.Parse("1995-03-11") },
                new Instructor { LastName = "Fakhouri", FirstMidName = "Fadi", HireDate = DateTime.Parse("2002-07-06") },
            };
            context.Instructors.AddRange(instructors);
            context.SaveChanges();

            var departments = new[]
            {
                new Department { Name = "English", Budget = 350000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[0].ID },
                new Department { Name = "Mathematics", Budget = 100000, StartDate = DateTime.Parse("2007-09-01"), InstructorID = instructors[1].ID },
            };
            context.Departments.AddRange(departments);
            context.SaveChanges();

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = departments[0].DepartmentID },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = departments[1].DepartmentID },
            };
            context.Courses.AddRange(courses);
            context.SaveChanges();

            var students = new[]
            {
                new Student { LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { LastName = "Anand", FirstMidName = "Arturo", EnrollmentDate = DateTime.Parse("2013-09-01") },
            };
            context.Students.AddRange(students);
            context.SaveChanges();

            var enrollments = new[]
            {
                new Enrollment { StudentID = students[0].ID, CourseID = 1050, Grade = Grade.A },
                new Enrollment { StudentID = students[1].ID, CourseID = 4022, Grade = Grade.B },
            };
            context.Enrollments.AddRange(enrollments);
            context.SaveChanges();

            var courseAssignments = new[]
            {
                new CourseAssignment { InstructorID = instructors[0].ID, CourseID = 1050 },
                new CourseAssignment { InstructorID = instructors[1].ID, CourseID = 4022 },
            };
            context.CourseAssignments.AddRange(courseAssignments);
            context.SaveChanges();

            context.OfficeAssignments.Add(new OfficeAssignment
            {
                InstructorID = instructors[0].ID,
                Location = "Smith 17"
            });
            context.SaveChanges();
        }
    }
}

using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            TestHelper.DrainNotificationQueue();
            _service = new NotificationService();
        }

        public void Dispose()
        {
            TestHelper.DrainNotificationQueue();
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_BasicOverload_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithDisplayName_EnqueuesWithDisplayNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.NotNull(notification);
            Assert.Contains("'John Doe'", notification.Message);
        }

        [Fact]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");

            var notification = _service.ReceiveNotification();

            Assert.Equal("TestUser", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_WithoutUserName_SetsSystemAsDefault()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = DateTime.Now.AddSeconds(-1);

            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.True(notification.CreatedAt >= before);
            Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
        }

        [Fact]
        public void ReceiveNotification_WhenEmpty_ReturnsNull()
        {
            var result = _service.ReceiveNotification();

            Assert.Null(result);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInOrder()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();
            var third = _service.ReceiveNotification();

            Assert.Equal("Student", first.EntityType);
            Assert.Equal("Course", second.EntityType);
            Assert.Null(third);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessage_ForOperation(EntityOperation operation, string expectedWord)
        {
            _service.SendNotification("Student", "1", "Test Student", operation);

            var notification = _service.ReceiveNotification();

            Assert.Contains(expectedWord, notification.Message, StringComparison.OrdinalIgnoreCase);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_MessageContainsId()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();

            Assert.Contains("ID: 42", notification.Message);
        }

        [Fact]
        public void SendNotification_WithDisplayName_MessageContainsName()
        {
            _service.SendNotification("Course", "1", "Chemistry", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();

            Assert.Contains("Course 'Chemistry'", notification.Message);
        }

        [Fact]
        public void MaxQueueLength_ExceedsLimit_TrimsQueue()
        {
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            int count = 0;
            while (_service.ReceiveNotification() != null) count++;

            Assert.True(count <= 500);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));

            Assert.Null(exception);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();

            var exception = Record.Exception(() => service.Dispose());

            Assert.Null(exception);
        }
    }
}

